%[text] ## Lab 1
%%
%[text] #### Harware parameters
T = 0.001; % sampling time (change to fit your experiment)

r = 0.01; % pinion gear radius [m]

Kt = 0.028; % torque constant for the EMB-AM2 actuator [Nm/A]

motor_eff = 1.0; % system efficiency (change to match your plant)

Kt = Kt*motor_eff; % including efficiency, actual Kt used in Simulink
%[text] #### Simulation Parameters
k_sim = 0;
b_sim = 0;
%%
%[text] ### Experiment 1: Quasi-statif determination of spring rates
S = 10;   % simulation duration time (change to fit your experiment)

t = 0:T:S;          % total time
y = zeros(size(t)); % output

slope = 5           % N/s  | Change the slope here %[output:6c1e9d3a]

% Delay
delay = 1         % seconds %[output:5df2d72a]
delay_t = 0:T:delay %[output:06aa41ea]

% Ramp
idx1 = (t >= 0) & (t < 2);
y(idx1) = t(idx1).*slope;

% Two sided
idx2 = (t >= 2) & (t < 4);
y(idx2) = t(idx2) .* -slope + slope*4;

% Mirrored
idx3 = (t >= 4) & (t < 6);
y(idx3) = (t(idx3) - 4) .* -slope;

% Mirrored Two-sided
idx4 = (t >= 6) & (t < 8);
y(idx4) = (t(idx4) - 6) .* slope - slope*2;

% delay y
y_delayed = [zeros(size(delay_t)), y(2:end)]; 
t = 0:T:S+delay;
size(t);
size(y_delayed);

plot(t, y_delayed, 'LineWidth', 2); %[output:751cf764]
xlabel('Time (s)'); %[output:751cf764]
ylabel('Amplitude'); %[output:751cf764]
title('Unit Ramp Function'); %[output:751cf764]
grid on; %[output:751cf764]

sim_input = timeseries(y_delayed', t');

% Define parameters
model_name = 'MSE_PLANT';

% Load and configure for Real-Time / External mode
load_system(model_name);
set_param(model_name, 'SimulationMode', 'external');

set_param(model_name, 'StopTime', num2str(S));

% Execute
set_param(model_name,'SimulationCommand','start')
%%
%[text] #### Plots
%[text] ![](text:image:339e)
%[text] ![](text:image:674a)
%[text] ![](text:image:12ba)![](text:image:9b06)
%[text] ![](text:image:2743)
%[text] ![](text:image:7de1)


%% PLOTTING - Input Force

plot(rt_time, f_input,'LineWidth',2); %[output:95adea50]
title('Input Force vs. Time'); %[output:95adea50]
xlabel('Time [s]'); %[output:95adea50]
ylabel('Force [N]'); %[output:95adea50]
legend('Input Force'); %[output:95adea50]
grid on; %[output:95adea50]

%% PLOTTING - Position for both Carts
plot(rt_time, cart1_position*100, rt_time, cart2_position*100,'LineWidth',2); %[output:42e28158]
title('Position vs. Time'); %[output:42e28158]
xlabel('Time [s]'); %[output:42e28158]
ylabel('Position [cm]'); %[output:42e28158]
legend('Cart1','Cart2'); %[output:42e28158]
grid on; %[output:42e28158]

plot(f_input, cart1_position, 'LineWidth', 2); %[output:92e49243]
title('Force vs displacement'); %[output:92e49243]
xlabel('Force (N)') %[output:92e49243]
ylabel('displacement') %[output:92e49243]
grid on; %[output:92e49243]

plot(rt_time, cart1_velocity, rt_time, cart2_velocity, 'LineWidth', 2); %[output:6d21a219]
title('Velocity vs Time'); %[output:6d21a219]
xlabel('Time [s]') %[output:6d21a219]
ylabel('Velocity [m/s]') %[output:6d21a219]
grid on; %[output:6d21a219]
%%
%[text] ### Experiment 2
%[text] Zero output: 
%[text] ![](text:image:8922)
%% ============================================================
% EXPERIMENT 2 - FREE VIBRATION / DISPLACEMENT DECAY
% Cart 1 is manually displaced before running
% =============================================================

clear;
clc;
close all;

%% Hardware Parameters

T = 0.001;                  % Sampling time [s]

r = 0.01;                   % Pinion gear radius [m]

Kt = 0.028;                 % EMB-AM2 torque constant [Nm/A]

motor_eff = 1.0;            % System efficiency

Kt = Kt*motor_eff;

k_sim = 0;
b_sim = 0;

%% Experiment Parameters

S = 20;                     % Test duration [s]
t = 0:T:S;                  % total time
y = zeros(size(t));         % output

sim_input = timeseries(y', t');

%% Load Model

model_name = 'MSE_PLANT';

load_system(model_name);

set_param(model_name,'SimulationMode','external');
set_param(model_name,'StopTime',num2str(S));

%% Start Experiment

disp('Cart 1 should already be displaced.'); %[output:3559d3ec]
disp('Starting free vibration test...'); %[output:9024c21e]

set_param(model_name,'SimulationCommand','start');

%% Wait for Completion

disp('Collecting data...'); %[output:28e0ff90]

while strcmp(get_param(model_name,'SimulationStatus'),'running')
    pause(0.1);
end

disp('Experiment Complete.'); %[output:98429597]
%%
%% ============================================================
% DISPLACEMENT RESPONSE
% =============================================================

figure; %[output:1fb8bd00]

plot(rt_time,cart1_position*100,... %[output:1fb8bd00]
    'b','LineWidth',2); %[output:1fb8bd00]

hold on; %[output:1fb8bd00]

plot(rt_time,cart2_position*100,... %[output:1fb8bd00]
    'r','LineWidth',2); %[output:1fb8bd00]

title('Free Vibration Response'); %[output:1fb8bd00]
xlabel('Time [s]'); %[output:1fb8bd00]
ylabel('Displacement [cm]'); %[output:1fb8bd00]
legend('Cart 1','Cart 2'); %[output:1fb8bd00]
grid on; %[output:1fb8bd00]

%% ============================================================
% VELOCITY RESPONSE (OPTIONAL)
% =============================================================

figure; %[output:8944c52b]

plot(rt_time,cart1_velocity,... %[output:8944c52b]
    'b','LineWidth',2); %[output:8944c52b]

hold on; %[output:8944c52b]

plot(rt_time,cart2_velocity,... %[output:8944c52b]
    'r','LineWidth',2); %[output:8944c52b]

title('Velocity Response'); %[output:8944c52b]
xlabel('Time [s]'); %[output:8944c52b]
ylabel('Velocity [m/s]'); %[output:8944c52b]
legend('Cart 1','Cart 2'); %[output:8944c52b]
grid on; %[output:8944c52b]

%% ============================================================
% LOG DECREMENT ANALYSIS
% USING CART 1 DISPLACEMENT
% =============================================================

x = cart1_position;
t = rt_time;

[pks,locs] = findpeaks(x,t,...
    'MinPeakProminence',0.05*max(abs(x)));

%% Plot Detected Peaks

figure; %[output:819198e6]

plot(t,x,'b','LineWidth',1.5); %[output:819198e6]
hold on; %[output:819198e6]

plot(locs,pks,... %[output:819198e6]
    'ro',... %[output:819198e6]
    'MarkerFaceColor','r'); %[output:819198e6]

title('Peak Detection for Log Decrement'); %[output:819198e6]
xlabel('Time [s]'); %[output:819198e6]
ylabel('Displacement [m]'); %[output:819198e6]
grid on; %[output:819198e6]

%% Damping Ratio Calculation

n = length(pks)-1;

if n >= 1 %[output:group:37a1373b]

    x1 = pks(1);
    xn = pks(end);

    delta = (1/n)*log(x1/xn);

    zeta = delta/sqrt(4*pi^2 + delta^2);

    fprintf('\n');
    fprintf('========== LOG DECREMENT RESULTS ==========\n'); %[output:24e615c7]
    fprintf('Number of cycles used: %d\n',n); %[output:2dbde381]
    fprintf('First peak: %.6f m\n',x1); %[output:63b051ac]
    fprintf('Last peak : %.6f m\n',xn); %[output:0fbd8ee6]
    fprintf('Log decrement: %.6f\n',delta); %[output:8626708e]
    fprintf('Damping ratio: %.6f\n',zeta); %[output:644c1d9d]

    %% Natural Frequency Estimate

    Td = mean(diff(locs));
    
    % Ignoring the first peak because it is noisy
    locs = locs(2:end);
    fd = 1/Td;
    wd = 2*pi*fd;

    wn = wd/sqrt(1-zeta^2);

    fprintf('Damped Frequency: %.3f Hz\n',fd); %[output:52f96f08]
    fprintf('Damped Angular Frequency: %.3f rad/s\n',wd); %[output:919017c7]
    fprintf('Natural Frequency: %.3f rad/s\n',wn); %[output:417956c7]
    fprintf('===========================================\n'); %[output:8c2f7004]

else

    warning('Not enough peaks detected for damping calculation.');

end %[output:group:37a1373b]
%%
%[text] ## Simulated Damping and Stiffness
k_sim = 0;
b_sim = 0;

